import{c as i,cG as l,cb as s,c8 as a,cf as e,cT as o,ce as n}from"./chunks/framework.BlkIsu1j.js";const t=JSON.parse('{"title":"附录 F：常见问题排查指南","description":"","frontmatter":{"title":"附录 F：常见问题排查指南","outline":"deep","layout":"doc","prev":"/ai/claudecodenew/appendix-e-cc-switch","next":"/ai/claudecodenew/appendix-g-glossary","date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/appendix-f-troubleshooting.md","filePath":"ai/claudecodenew/appendix-f-troubleshooting.md","lastUpdated":1780121796000}'),d={id:"frontmatter-title",tabindex:"-1"};const c=i({name:"ai/claudecodenew/appendix-f-troubleshooting.md"},[["render",function(i,t,c,p,r,h){return l(),s("div",null,[a("h1",d,[e(o(i.$frontmatter.title)+" ",1),t[0]||(t[0]=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),t[1]||(t[1]=n('<h2 id="安装与启动" tabindex="-1">安装与启动 <a class="header-anchor" href="#安装与启动" aria-label="Permalink to “安装与启动”">​</a></h2><h3 id="vscode-扩展无法安装" tabindex="-1">VSCode 扩展无法安装 <a class="header-anchor" href="#vscode-扩展无法安装" aria-label="Permalink to “VSCode 扩展无法安装”">​</a></h3><p><strong>症状</strong>：在 VSCode 扩展市场搜索不到 Claude Code 扩展，或安装后扩展未激活。</p><p><strong>原因</strong>：</p><ul><li>VSCode 版本过低（需 1.82+）</li><li>网络代理或防火墙阻止扩展市场访问</li><li>扩展与现有插件冲突</li></ul><p><strong>解决方案</strong>：</p><ol><li>升级 VSCode 到最新版本（Code &gt; Check for Updates）</li><li>检查网络代理设置，确保 <code>https://marketplace.visualstudio.com</code> 可访问</li><li>尝试通过命令行安装：<code>code --install-extension anthropic.claude-code</code></li><li>暂时禁用其他 AI 编程扩展（如 Copilot、Cody），排查冲突</li></ol><h3 id="cli-命令找不到" tabindex="-1">CLI 命令找不到 <a class="header-anchor" href="#cli-命令找不到" aria-label="Permalink to “CLI 命令找不到”">​</a></h3><p><strong>症状</strong>：终端中运行 <code>claude</code> 提示 <code>command not found</code>。</p><p><strong>原因</strong>：</p><ul><li>Node.js 未安装或版本过低（需 18+）</li><li>npm 全局安装路径未加入 PATH</li><li>使用 pnpm/npx 安装时链接未正确创建</li></ul><p><strong>解决方案</strong>：</p><ol><li>确认 Node.js 版本：<code>node --version</code>，需 ≥ 18</li><li>确认安装状态：<code>npm list -g @anthropic-ai/claude-code</code></li><li>重新安装：<code>npm install -g @anthropic-ai/claude-code</code></li><li>检查 PATH：<code>echo $PATH</code>，确认 npm 全局 bin 目录在其中（通常是 <code>~/.npm-global/bin</code> 或 <code>/usr/local/bin</code>）</li><li>重启终端使 PATH 生效</li></ol><h3 id="首次启动认证失败" tabindex="-1">首次启动认证失败 <a class="header-anchor" href="#首次启动认证失败" aria-label="Permalink to “首次启动认证失败”">​</a></h3><p><strong>症状</strong>：运行 <code>claude</code> 后浏览器打开 OAuth 页面，但授权后终端仍提示未认证。</p><p><strong>原因</strong>：</p><ul><li>浏览器网络环境与终端不同（如终端走代理但浏览器不走）</li><li>Anthropic 账号未完成 API 额度开通</li><li>OAuth 回调端口被占用或防火墙阻止</li></ul><p><strong>解决方案</strong>：</p><ol><li>确认已在 console.anthropic.com 完成账号注册和 API Key 生成</li><li>使用 API Key 直接认证：运行 <code>claude login --api-key</code> 并粘贴你的 key</li><li>检查防火墙是否放行本地回环端口（通常是 45454）</li><li>尝试 <code>claude logout</code> 后重新 <code>claude login</code></li></ol><h2 id="模型与-api" tabindex="-1">模型与 API <a class="header-anchor" href="#模型与-api" aria-label="Permalink to “模型与 API”">​</a></h2><h3 id="api-调用超时" tabindex="-1">API 调用超时 <a class="header-anchor" href="#api-调用超时" aria-label="Permalink to “API 调用超时”">​</a></h3><p><strong>症状</strong>：Claude 响应时间过长，最终显示超时错误，或操作中断。</p><p><strong>原因</strong>：</p><ul><li>网络延迟过高（尤其是国内访问 Anthropic API）</li><li>请求上下文过大，模型处理时间增加</li><li>Anthropic 服务端负载高或正在维护</li><li>本地代理配置不当导致连接不稳定</li></ul><p><strong>解决方案</strong>：</p><ol><li>检查 Anthropic 服务状态：访问 status.anthropic.com</li><li>缩小上下文：使用 <code>/compact</code> 压缩对话历史，或减少 <code>.claude/settings.json</code> 中 <code>permissions.allow</code> 的文件范围</li><li>优化代理设置：如使用代理，确保为 HTTPS 长连接优化，建议使用 HTTP/2 代理</li><li>设置更长的超时时间：在 <code>.claude/settings.json</code> 中调整 <code>timeout</code> 字段（单位毫秒）</li><li>如果是企业用户，联系 Anthropic 销售开通专用带宽</li></ol><h3 id="token-配额耗尽" tabindex="-1">Token 配额耗尽 <a class="header-anchor" href="#token-配额耗尽" aria-label="Permalink to “Token 配额耗尽”">​</a></h3><p><strong>症状</strong>：API 返回 429 错误，提示 rate limit 或 quota exceeded。</p><p><strong>原因</strong>：</p><ul><li>达到 API Key 的速率限制（按 RPM/TPM 计）</li><li>月度配额已用完</li><li>并发请求过多</li></ul><p><strong>解决方案</strong>：</p><ol><li>查看当前用量：console.anthropic.com &gt; API Keys &gt; Usage</li><li>降低对话频率，避免短时间内发送大量请求</li><li>使用 <code>/compact</code> 减少上下文 token 消耗</li><li>升级 API 套餐或在 console 中申请提额</li><li>对于团队使用，建议为每个开发者创建独立 API Key 以分散配额</li></ol><h3 id="模型响应质量差" tabindex="-1">模型响应质量差 <a class="header-anchor" href="#模型响应质量差" aria-label="Permalink to “模型响应质量差”">​</a></h3><p><strong>症状</strong>：Claude 给出的回答不准确、不完整，或产生幻觉。</p><p><strong>原因</strong>：</p><ul><li>使用的模型版本过旧（如 Claude 3 Haiku）</li><li>提示词不够明确，缺少必要上下文</li><li>对话历史过长导致注意力分散</li><li>CLAUDE.md 缺少关键项目信息</li></ul><p><strong>解决方案</strong>：</p><ol><li>确认当前使用的模型：检查 <code>.claude/settings.json</code> 中的 <code>model</code> 字段，或在对话中用 <code>/model</code> 查看</li><li>切换到更强大的模型：<code>/model</code> 选择 Claude 4 Sonnet 或 Opus</li><li>优化 CLAUDE.md：补充项目架构、常用命令和编码规范，帮助 Claude 理解上下文</li><li>使用 <code>/compact</code> 清除无关对话，保留关键决策信息</li><li>将复杂问题拆分为多个简单问题逐步解决</li><li>在对话中使用 <code>@file</code> 明确指定需要关注的文件</li></ol><h3 id="cc-switch-模型切换无效" tabindex="-1">cc-switch 模型切换无效 <a class="header-anchor" href="#cc-switch-模型切换无效" aria-label="Permalink to “cc-switch 模型切换无效”">​</a></h3><p><strong>症状</strong>：运行 <code>cc-switch</code> 命令后，实际使用的模型未变化。</p><p><strong>原因</strong>：</p><ul><li>配置文件路径错误或权限不足</li><li>多个配置文件冲突（全局 vs 项目级）</li><li>目标模型在你的 API 层级不可用</li><li>VSCode 扩展缓存了旧配置未刷新</li></ul><p><strong>解决方案</strong>：</p><ol><li>手动检查配置文件：<code>cat ~/.claude/settings.json</code> 和项目目录下 <code>.claude/settings.json</code></li><li>确认目标模型在你的 API tier 中可用（console.anthropic.com &gt; Limits）</li><li>运行 <code>claude --version</code> 确认 CLI 版本支持目标模型</li><li>VSCode 用户：重启扩展或执行 <code>Cmd+Shift+P</code> &gt; <code>Developer: Reload Window</code></li><li>如配置文件冲突，项目级配置优先，删除或合并全局配置中的模型设置</li></ol><h2 id="权限问题" tabindex="-1">权限问题 <a class="header-anchor" href="#权限问题" aria-label="Permalink to “权限问题”">​</a></h2><h3 id="操作被拒绝但应该允许" tabindex="-1">操作被拒绝但应该允许 <a class="header-anchor" href="#操作被拒绝但应该允许" aria-label="Permalink to “操作被拒绝但应该允许”">​</a></h3><p><strong>症状</strong>：Claude 拒绝执行某个操作（如读取文件、运行命令），提示权限不足。</p><p><strong>原因</strong>：</p><ul><li>项目 <code>.claude/settings.json</code> 中的 <code>permissions.deny</code> 列表包含了该操作</li><li>全局 <code>~/.claude/settings.json</code> 继承了拒绝策略</li><li>该操作类型的默认行为是&quot;先询问后执行&quot;，响应超时被当作拒绝</li></ul><p><strong>解决方案</strong>：</p><ol><li>检查项目 <code>.claude/settings.json</code> 和全局 <code>~/.claude/settings.json</code> 中的 <code>permissions.deny</code> 配置</li><li>如需允许，将对应命令或路径添加到 <code>permissions.allow</code>：<div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(npm test:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Read(/path/to/project/**)&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li>使用更具体的 allow 规则可覆盖 deny 规则</li><li>确认操作类型在 <code>.claude/settings.json</code> 中未被设为 <code>&quot;ask&quot;</code>（需用户确认），如不需要确认可设为 <code>&quot;allow&quot;</code></li></ol><h3 id="权限弹窗太多" tabindex="-1">权限弹窗太多 <a class="header-anchor" href="#权限弹窗太多" aria-label="Permalink to “权限弹窗太多”">​</a></h3><p><strong>症状</strong>：每次操作都弹出确认对话框，严重影响工作效率。</p><p><strong>原因</strong>：</p><ul><li>项目配置中将多个常用操作设置为&quot;始终询问&quot;模式</li><li>未配置 <code>.claude/settings.json</code>，Claude 对高风险操作默认需要确认</li><li>权限规则写得太宽泛，每次匹配到的路径不同</li></ul><p><strong>解决方案</strong>：</p><ol><li>在项目 <code>.claude/settings.json</code> 中配置常用操作的自动允许：<div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git diff:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git status:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(npm run:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Read(./src/**)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Write(./src/**)&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li>使用通配符 <code>*</code> 和 <code>**</code> 匹配多路径，减少逐条配置</li><li>对于完全不希望被允许的操作，在 <code>deny</code> 中明确声明，避免触发确认</li><li>运行 <code>claude --dangerously-skip-permissions</code> 在可信项目中跳过所有权限检查（仅限临时使用）</li></ol><h3 id="危险操作没有被阻止" tabindex="-1">危险操作没有被阻止 <a class="header-anchor" href="#危险操作没有被阻止" aria-label="Permalink to “危险操作没有被阻止”">​</a></h3><p><strong>症状</strong>：Claude 执行了你不希望它执行的危险操作，如删除了重要文件。</p><p><strong>原因</strong>：</p><ul><li><code>permissions.allow</code> 配置过于宽松，匹配到了危险操作</li><li>全局配置中的 deny 规则不够全面</li><li>未使用 <code>permissions.deny</code> 明确禁止特定操作</li></ul><p><strong>解决方案</strong>：</p><ol><li>在 <code>permissions.deny</code> 中添加危险操作黑名单：<div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(rm -rf:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git push --force:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git reset --hard:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Write(./.env)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Write(./.git/**)&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li>使用版本控制（Git），危险操作后可通过 <code>git checkout</code> 恢复</li><li>定期审查 <code>.claude/settings.json</code> 中的权限规则，确保 allow 规则不过度宽松</li><li>在 settings.json 中设置 <code>&quot;permissionMode&quot;: &quot;default&quot;</code> 恢复默认安全策略</li></ol><h2 id="上下文问题" tabindex="-1">上下文问题 <a class="header-anchor" href="#上下文问题" aria-label="Permalink to “上下文问题”">​</a></h2><h3 id="claude-忘记之前的对话" tabindex="-1">Claude 忘记之前的对话 <a class="header-anchor" href="#claude-忘记之前的对话" aria-label="Permalink to “Claude 忘记之前的对话”">​</a></h3><p><strong>症状</strong>：对话进行到一半，Claude 突然不记得之前讨论过的内容。</p><p><strong>原因</strong>：</p><ul><li>对话 token 数超过了模型上下文窗口（自动压缩时丢弃了较早的消息）</li><li>手动或自动 <code>/compact</code> 压缩掉了关键信息</li><li>会话被中断后恢复（如网络断开重连），部分历史丢失</li></ul><p><strong>解决方案</strong>：</p><ol><li>使用 <code>/compact</code> 前手动检查压缩摘要——确认关键信息被保留，否则取消并在提示中重申</li><li>在 CLAUDE.md 中记录持久化的项目上下文（架构、约定），这部分不会被压缩</li><li>将重要的阶段性结论写入项目文档或 TODO，而非仅保留在对话中</li><li>开启长对话时，定期要求 Claude 回顾并总结当前进度，将总结写入 <code>PLAN.md</code> 或项目文件中</li><li>使用 <code>/context</code> 查看当前上下文使用情况，在接近上限前提早规划</li></ol><h3 id="上下文用量过大" tabindex="-1">上下文用量过大 <a class="header-anchor" href="#上下文用量过大" aria-label="Permalink to “上下文用量过大”">​</a></h3><p><strong>症状</strong>：对话初始响应很快，但随着对话推进越来越慢，<code>/context</code> 显示接近或达到上限。</p><p><strong>原因</strong>：</p><ul><li>对话中包含了过多的大文件内容</li><li>大量中间输出（如反复测试的日志）留在上下文中</li><li>未及时压缩，冗余信息占据窗口</li></ul><p><strong>解决方案</strong>：</p><ol><li>定期运行 <code>/compact</code> 压缩对话，保留摘要</li><li>避免一次性读取过多大文件；使用 grep 定位关键部分再读取</li><li>将阶段性输出写入文件（用 Write 工具），而不是全部留在对话中</li><li>开启新对话处理独立任务，而非在一个长对话中完成所有事</li><li>在 CLAUDE.md 中写好项目背景，减少每次对话需要加载的冗余上下文</li><li>使用 <code>/context</code> 监控用量，提前规划压缩时机</li></ol><h3 id="compact-后丢失关键信息" tabindex="-1">/compact 后丢失关键信息 <a class="header-anchor" href="#compact-后丢失关键信息" aria-label="Permalink to “/compact 后丢失关键信息”">​</a></h3><p><strong>症状</strong>：执行 <code>/compact</code> 后，Claude 不再知道之前讨论的重要细节。</p><p><strong>原因</strong>：</p><ul><li>自动生成的压缩摘要没有包含你认为重要的信息</li><li>压缩算法无法识别哪些是&quot;关键信息&quot;，仅按通用策略保留摘要</li><li>压缩后模型上下文被清空，只保留压缩摘要</li></ul><p><strong>解决方案</strong>：</p><ol><li><strong>在压缩前</strong>，手动要求 Claude 总结当前进展的关键信息，并写入文件或明确告知&quot;请记住以下几点&quot;</li><li>压缩后立即测试：问 Claude 一个只有在前段对话中才讨论过的细节，看是否还记得</li><li>如果不满意压缩结果，使用 Git 恢复对话前的状态（如对话日志有备份）</li><li>将重要信息持久化：写入项目 <code>CLAUDE.md</code>、<code>TODO.md</code> 或在对话中明确要求 Claude 在压缩后主动回顾关键约束</li><li>考虑在关键决策点开新对话，而非无限延长单次对话</li></ol><h2 id="代码编辑问题" tabindex="-1">代码编辑问题 <a class="header-anchor" href="#代码编辑问题" aria-label="Permalink to “代码编辑问题”">​</a></h2><h3 id="claude-修改了不该改的文件" tabindex="-1">Claude 修改了不该改的文件 <a class="header-anchor" href="#claude-修改了不该改的文件" aria-label="Permalink to “Claude 修改了不该改的文件”">​</a></h3><p><strong>症状</strong>：Claude 在解决一个问题时，修改了无关文件或产生了意料之外的变更。</p><p><strong>原因</strong>：</p><ul><li>任务描述不够精确，Claude 自行扩大了修改范围</li><li>CLAUDE.md 中缺乏代码规范说明，Claude 按自身理解做了格式化或重构</li><li>上下文中有误导性的信息，引导 Claude 做出错误判断</li></ul><p><strong>解决方案</strong>：</p><ol><li>明确指定只修改哪些文件：例如 &quot;只修改 <code>src/utils.ts</code>，不要动其他文件&quot;</li><li>在 CLAUDE.md 中说明项目的代码风格规范，禁止自动格式化</li><li>使用 Git 审查每次 Claude 的变更：<code>git diff</code> 检查变更范围</li><li>每次修改后立即提交，避免积累过多未审查的变更</li><li>如果发生意外修改，使用 <code>git checkout -- &lt;file&gt;</code> 恢复未预期的变更</li></ol><h3 id="diff-显示异常" tabindex="-1">Diff 显示异常 <a class="header-anchor" href="#diff-显示异常" aria-label="Permalink to “Diff 显示异常”">​</a></h3><p><strong>症状</strong>：Claude 生成的 diff 无法正常应用，或显示的变更与实际不符。</p><p><strong>原因</strong>：</p><ul><li>文件在 Claude 修改期间被外部程序改动（如编辑器自动保存）</li><li>文件编码问题（如 UTF-8 BOM、CRLF vs LF）</li><li>diff 中的上下文行数与文件当前状态不匹配</li></ul><p><strong>解决方案</strong>：</p><ol><li>在 Claude 修改文件前，保存并关闭其他编辑器中的该文件</li><li>统一文件编码和换行符：在项目根目录配置 <code>.editorconfig</code>：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>root = true</span></span>\n<span class="line"><span>[*]</span></span>\n<span class="line"><span>charset = utf-8</span></span>\n<span class="line"><span>end_of_line = lf</span></span></code></pre></div></li><li>使用 <code>git diff</code> 查看实际变更，手动解决冲突</li><li>如果 diff 应用失败，将当前文件内容提供给 Claude，要求其基于最新内容重新生成修改</li></ol><h3 id="内联编辑不触发" tabindex="-1">内联编辑不触发 <a class="header-anchor" href="#内联编辑不触发" aria-label="Permalink to “内联编辑不触发”">​</a></h3><p><strong>症状</strong>：在 VSCode 中选中代码后，内联编辑 (Inline Edit) 功能没有弹出或无法使用。</p><p><strong>原因</strong>：</p><ul><li>Claude Code 扩展未激活或需要重新加载</li><li>内联编辑功能在当前文件类型/语言中不支持</li><li>VSCode 快捷键冲突</li><li>扩展版本过旧，尚未支持该功能</li></ul><p><strong>解决方案</strong>：</p><ol><li>确认扩展已激活：VSCode 状态栏应显示 Claude 图标，点击可查看状态</li><li>重新加载窗口：<code>Cmd+Shift+P</code> &gt; <code>Developer: Reload Window</code></li><li>检查快捷键绑定：内联编辑默认快捷键为 <code>Cmd+I</code>（Mac）/ <code>Ctrl+I</code>（Windows），确认未被其他扩展占用</li><li>更新扩展到最新版本</li><li>尝试在 <code>.ts</code>, <code>.js</code>, <code>.py</code>, <code>.md</code> 等已验证支持的文件类型中测试</li><li>如仍无效，使用终端模式 <code>/edit</code> 命令作为替代</li></ol><h2 id="性能问题" tabindex="-1">性能问题 <a class="header-anchor" href="#性能问题" aria-label="Permalink to “性能问题”">​</a></h2><h3 id="claude-响应很慢" tabindex="-1">Claude 响应很慢 <a class="header-anchor" href="#claude-响应很慢" aria-label="Permalink to “Claude 响应很慢”">​</a></h3><p><strong>症状</strong>：发送消息后，等待很长时间才能收到 Claude 的回复。</p><p><strong>原因</strong>：</p><ul><li>上下文过大，模型处理时间长</li><li>网络到 Anthropic API 的延迟高</li><li>使用的模型较重（如 Opus 比 Sonnet 慢）</li><li>Anthropic 服务端排队（高峰时段）</li><li>本地项目中大型文件的索引导致预处理延迟</li></ul><p><strong>解决方案</strong>：</p><ol><li>使用 <code>/context</code> 检查当前 token 用量，如接近上限则 <code>/compact</code></li><li>切换到更快的模型：<code>/model</code> 选择 Claude 4 Sonnet（比 Opus 快 2-3 倍）</li><li>测试网络延迟：<code>curl -w &quot;\\ntime_total: %{time_total}s\\n&quot; https://api.anthropic.com/v1/messages</code></li><li>避免在高峰时段使用（北美上午 9-12 点 PT 为高峰）</li><li>使用 <code>--model</code> 参数指定模型跳过自动检测</li><li>将项目中的大型非必要文件加入 <code>.gitignore</code> 或 <code>.claudeignore</code> 减少索引范围</li></ol><h3 id="大项目加载慢" tabindex="-1">大项目加载慢 <a class="header-anchor" href="#大项目加载慢" aria-label="Permalink to “大项目加载慢”">​</a></h3><p><strong>症状</strong>：在大型项目中启动 Claude 或切换会话时，初始化/索引阶段耗时很长。</p><p><strong>原因</strong>：</p><ul><li>项目中文件数量庞大（node_modules、dist 等未排除）</li><li>CLAUDE.md 中引用了大量文件或目录</li><li>项目配置文件（如 tsconfig.json）解析复杂</li></ul><p><strong>解决方案</strong>：</p><ol><li>创建 <code>.claudeignore</code> 文件排除不需要索引的目录：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>node_modules/</span></span>\n<span class="line"><span>.vitepress/dist/</span></span>\n<span class="line"><span>.git/</span></span>\n<span class="line"><span>*.min.js</span></span>\n<span class="line"><span>*.map</span></span></code></pre></div></li><li>精简 CLAUDE.md：移除不必要的文件引用，保持简洁的项目概述</li><li>使用 <code>/add-dir</code> 逐步添加工作目录，而非在启动时索引整个项目</li><li>对大型 monorepo，在子包目录中创建独立的 <code>.claude/settings.json</code>，分而治之</li><li>定期清理项目：删除未使用的依赖、构建产物和临时文件</li></ol><h3 id="频繁超时" tabindex="-1">频繁超时 <a class="header-anchor" href="#频繁超时" aria-label="Permalink to “频繁超时”">​</a></h3><p><strong>症状</strong>：Claude 操作（读文件、执行命令、等待 API 响应）频繁超时。</p><p><strong>原因</strong>：</p><ul><li>网络不稳定，丢包率高</li><li>代理服务器连接池耗尽</li><li>请求的 token 数量巨大</li><li>本地系统资源不足（内存、CPU）</li></ul><p><strong>解决方案</strong>：</p><ol><li>检查网络稳定性：<code>ping -c 20 api.anthropic.com</code> 观察丢包率</li><li>如使用代理，检查代理服务器状态和连接数限制</li><li>减少单次请求的 token 量：分批处理大量文件，而非一次性全部读取</li><li>在 <code>.claude/settings.json</code> 中增加超时时间：<div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;timeout&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">120000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li>关闭其他占用网络带宽的应用（视频会议、大文件下载）</li><li>检查系统资源：确保有足够的空闲内存（建议 ≥ 4GB），CPU 负载不过高</li><li>尝试切换到不同的网络（如从 Wi-Fi 切换到有线，或更换 DNS）</li></ol>',120))])}]]);export{t as __pageData,c as default};
